import pandas as pd

def _mean_from_hourly_df(df, value_col, county_label):
    if df is None or len(df) == 0:
        raise ValueError(f"{county_label}在目标日期无小时数据，不能静默输出0或空值。")
    if value_col not in df.columns:
        raise KeyError(f"{county_label}数据缺少必要指标：{value_col}")
    val = pd.to_numeric(df[value_col], errors="coerce").mean()
    if pd.isna(val):
        raise ValueError(f"{county_label}的{value_col}均值为缺失值，不能赋值。")
    return float(val)

